sys_security_acl.script:
answer = selfServiceACLCondition(current);

function selfServiceACLCondition(current) {
	var i, requiredRoles;

	//If either of these fields does not exist, then the self-service deploy
	// application is probably not installed, so return false.
	if (
		!current.isValidField('x_taniu_selfdeploy_self_service_installable') ||
		!current.isValidField('x_taniu_selfdeploy_self_service_required_roles')
	) {
		return false;
	}

	//If package is not self-service deployable, then return false.
	if (current.getValue('x_taniu_selfdeploy_self_service_installable') !== '1') {
		return false;
	}

	//If self-service deployable is true and the roles field is empty, then
	// return true.


	//If self-service deployable is true and the user has the required
	// roles, then return true.
	requiredRoles = current.getValue('x_taniu_selfdeploy_self_service_required_roles');
	if (!requiredRoles) {
		return gs.getSession().isLoggedIn();
	}

	requiredRoles = requiredRoles.split(',');

	for (i = 0; i < requiredRoles.length; i++) {
		if (gs.hasRole(requiredRoles[i])) {
			return true;
		}
	}

	//If self-service deployable is true and the user does NOT have the required
	// roles, then we get here. If we got here, return false.
	return false;
}
